   586	const char*
   587	parse_oct(const char* s, std::uint32_t& v)
   588	{
   589	  if (*s < '0' || *s > '9')
   590	    return nullptr;
   591	  std::uint32_t num = 0;
   592	  while ('0' <= *s && *s <= '9') {
   593	    num = num * 10 + (*s - '0');
   594	    ++s;
   595	  }
   596	  v = num;
   597	  return s;
   598	}
