   600	/// 把 \p texp 的里面翻出来，因为 C 的类型表达式与表达式内外顺序是相反的。
   601	TypeExpr*
   602	turn_texp(TypeExpr* texp)
   603	{
   604	  if (texp->sub == nullptr)
   605	    return texp;
   606	  auto innerMost = turn_texp(texp->sub);
   607	  innerMost->sub = texp;
   608	  texp->sub = nullptr;
   609	  return innerMost;
