   614	const char*
   615	Json2Asg::parse_type(const char* s, const Type*& v)
   616	{
   617	  auto ty = make<Type>();
   618	  s = parse_base(s, *ty);
   619	  if (!s)
   620	    return nullptr;
   621	
   622	  while (true) {
   623	    auto p = parse_base(skip_spaces(s), *ty);
   624	    if (!p)
   625	      break;
   626	    s = p;
   627	  }
   628	
   629	  s = parse_texp(skip_spaces(s), ty->texp);
   630	  if (ty->texp)
   631	    ty->texp = turn_texp(ty->texp); // 将类型表达式内外翻转
   632	
   633	  v = ty;
   634	  return s;
   635	}
