   653	    if (!p)
   654	      goto RULE_2;
   655	    auto arrTy = make<ArrayType>();
   656	    arrTy->len = len;
   657	    v = arrTy;
   658	    return p;
   659	  }
   660	
   661	RULE_2:
   662	  if (auto p = match(s, "(")) {
   663	    std::vector<const Type*> params;
   664	    p = parse_args(skip_spaces(p), params);
   665	    if (!p)
   666	      goto RULE_3;
   667	    p = match(skip_spaces(p), ")");
   668	    if (!p)
   669	      goto RULE_3;
   670	    auto funTy = make<FunctionType>();
   671	    funTy->params = std::move(params);
   672	    v = funTy;
   673	    return p;
   674	  }
   675	
   676	RULE_3:
   677	  if (auto p = match(s, "(")) {
   678	    p = parse_texp(skip_spaces(p), v);
   679	    if (!p)
   680	      goto EMPTY;
   681	    p = match(skip_spaces(p), ")");
   682	    if (!p)
   683	      goto EMPTY;
   684	    return p;
   685	  }
   686	
   687	EMPTY:
   688	  v = nullptr;
   689	  return s;
   690	}
   691	
   692	const char*
   693	Json2Asg::parse_texp_1(const char* s, TypeExpr*& v)
   694	{
   695	  TypeExpr* texp;
   696	  auto p = parse_texp_0(s, texp);
   697	  if (!p)
   698	    return nullptr;
   699	  if (s != p) {
   700	    while (true) {
   701	      s = p;
   702	      TypeExpr* sup;
   703	      p = parse_texp_0(skip_spaces(p), sup);
   704	      if (!p)
   705	        return nullptr;
   706	      if (s == p)
   707	        break;
   708	      sup->sub = texp;
   709	      texp = sup;
   710	    }
   711	  }
   712	  v = texp;
   713	  return s;
   714	}
   715	
   716	const char*
   717	Json2Asg::parse_texp_2(const char* s, TypeExpr*& v)
   718	{
   719	RULE_1:
   720	  if (auto p = match(s, "*")) {
   721	    TypeExpr* texp;
   722	    p = parse_texp_2(skip_spaces(p), texp);
   723	    if (!p)
   724	      goto EMPTY;
   725	    v = make<PointerType>();
   726	    v->sub = texp;
   727	    return p;
   728	  }
   729	
   730	RULE_2:
   731	  if (auto p = parse_texp_1(s, v))
   732	    return p;
   733	
   734	EMPTY:
   735	  return nullptr;
   736	}
