   738	const char*
   739	Json2Asg::parse_args(const char* s, std::vector<const Type*>& v)
   740	{
   741	  const Type* ty;
   742	  auto p = parse_type(s, ty);
   743	  if (!p)
   744	    return s; // 没有参数的情况也是合法的
   745	  s = p;
   746	
   747	  std::vector<const Type*> params;
   748	  params.push_back(ty);
   749	
   750	  while (true) {
   751	    p = match(skip_spaces(s), ",");
   752	    if (!p)
   753	      break;
   754	
   755	    p = parse_type(skip_spaces(p), ty);
   756	    if (!p)
   757	      return nullptr;
   758	
   759	    params.push_back(ty);
   760	    s = p;
   761	  }
   762	
   763	  v = std::move(params);
   764	  return s;
   765	}
